21	const basePremiumByType: Record<string, number> = {
22	  amulet: 60,
23	  sword: 100,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const PROCESSING_FEE = 5;
31	const BLOCK_OF_THREE_PREMIUM = 60;
32	const LOYAL_CUSTOMER_PREMIUM = 95;
33	
34	function surchargeFactorFor(item: Item): number {
35	  if (item.cursed) return 1.5;
36	  if ((item.enchantment ?? 0) >= 5) return 1.3;
37	  return 1;
38	}
39	
40	function surchargeFor(item: Item): number {
41	  return basePremiumByType[item.type] * (surchargeFactorFor(item) - 1);
42	}
43	
44	function premiumForTypeBlock(type: string, count: number): number {
45	  if (count === 3) return BLOCK_OF_THREE_PREMIUM;
46	  return count * basePremiumByType[type];
47	}
48	
49	export function quote(
50	  _customer: Customer,
51	  items: Item[],
52	  _options: QuoteOptions = {},
53	): QuoteResult {
54	  const countByType = items.reduce<Record<string, number>>((counts, item) => {
55	    counts[item.type] = (counts[item.type] ?? 0) + 1;
56	    return counts;
57	  }, {});
58	  const baseWithoutSurcharges = Object.entries(countByType).reduce(
59	    (sum, [type, count]) => sum + premiumForTypeBlock(type, count),
60	    0,
61	  );
62	  const surcharges = items.reduce((sum, item) => sum + surchargeFor(item), 0);
63	  const basePremium = baseWithoutSurcharges + surcharges;
64	  const premium =
65	    items.length === 0
66	      ? PROCESSING_FEE
67	      : _customer.yearsWithMHPCO >= 2
68	        ? LOYAL_CUSTOMER_PREMIUM
69	        : 0;
70	  return { basePremium, premium };
71	}
